@ExtendWith(MockitoExtension::class)
class CallServiceTest {

    @Mock
    private lateinit var repository: CallRepository

    @InjectMocks
    private lateinit var service: CallService

    @Test
    fun `should initiate call successfully`() {
        // given
        val callerId = "user-1"
        val calleeId = "user-2"
        val callEntity = CallEntity(
            id = "call-1",
            callerId = callerId,
            calleeId = calleeId,
            status = CallStatus.INITIATED.value,
        )
        `when`(repository.save(any())).thenReturn(callEntity)

        // when
        val result = service.initiateCall(callerId, calleeId)

        // then
        assertThat(result.id).isEqualTo("call-1")
        assertThat(result.status).isEqualTo(CallStatus.INITIATED.value)
    }

    @Test
    fun `should throw when callee not found`() {
        // given
        `when`(userService.getUserInfo("invalid")).thenThrow(NotFoundException())

        // when & then
        assertThrows<NotFoundException> {
            service.initiateCall("caller", "invalid")
        }
    }
}
