### 주요 클래스 패턴

**CallService (통화 생성/종료)**:
```kotlin
@Service
class CallService(
    private val callRepository: CallRepository,
    private val userService: UserService,
    private val eventPublisher: ApplicationEventPublisher,
) {
    @Transactional
    fun initiateCall(callerId: String, calleeId: String): CallEntity {
        val call = CallEntity(
            callerId = callerId,
            calleeId = calleeId,
            status = CallStatus.INITIATED.value,
            initiatedAt = LocalDateTime.now(),
        )
        val saved = callRepository.save(call)
        eventPublisher.publishEvent(CallInitiatedEvent(saved))
        return saved
    }

    @Transactional
    fun endCall(callId: String, duration: Long): CallEntity {
        val call = callRepository.findById(callId).orElseThrow()
        call.apply {
            status = CallStatus.COMPLETED.value
            endedAt = LocalDateTime.now()
            durationSeconds = duration
        }
        return callRepository.save(call)
    }
}
```

**CallGrpcService (gRPC 엔드포인트)**:
```kotlin
@GrpcService
class CallGrpcService(
    private val callService: CallService,
) : CallServiceGrpc.CallServiceImplBase() {

    override fun initiateCall(
        request: InitiateCallRequest,
        responseObserver: StreamObserver<InitiateCallResponse>,
    ) {
        try {
            val call = callService.initiateCall(
                callerId = request.callerId,
                calleeId = request.calleeId,
            )
            val response = InitiateCallResponse.newBuilder()
                .setCall(call.toProto())
                .build()
            responseObserver.onNext(response)
            responseObserver.onCompleted()
        } catch (e: Exception) {
            responseObserver.onError(
                Status.INTERNAL
                    .withDescription(e.message)
                    .asRuntimeException()
            )
        }
    }
}
```

