### GraphQL Service (graphql 모듈)

**graphql/src/main/kotlin/com/maum/backend/service/call/CallService.kt**:

```kotlin
@Service
class CallService {
    @GrpcClient("call-grpc")
    private lateinit var callStub: CallServiceGrpc.CallServiceBlockingStub

    fun initiateCall(callerId: String, calleeId: String): InitiateCallResponse {
        val request = InitiateCallRequest.newBuilder()
            .setCallerId(callerId)
            .setCalleeId(calleeId)
            .build()
        return try {
            callStub.initiateCall(request)
        } catch (e: StatusRuntimeException) {
            throw CustomGraphQLException(
                code = e.status.code.name,
                message = e.status.description ?: "Call service error"
            )
        }
    }

    fun getCallStatus(callId: String): GetCallStatusResponse {
        val request = GetCallStatusRequest.newBuilder()
            .setCallId(callId)
            .build()
        return callStub.getCallStatus(request)
    }

    fun listCallRecords(userId: String, limit: Int, offset: Int): ListCallRecordsResponse {
        val request = ListCallRecordsRequest.newBuilder()
            .setUserId(userId)
            .setLimit(limit)
            .setOffset(offset)
            .build()
        return callStub.listCallRecords(request)
    }
}
```

### GraphQL Controller (graphql 모듈)

**graphql/src/main/kotlin/com/maum/backend/controller/call/CallController.kt**:

```kotlin
@Controller
class CallController(
    private val callService: CallService,
    private val userService: UserService,
) {
    @MutationMapping
    @PreAuthorize("hasAuthority('User')")
    fun initiateCall(
        @UserId callerId: String,
        @Argument input: InitiateCallInput,
    ): CallResponse {
        val response = callService.initiateCall(callerId, input.calleeId)
        return response.call.toResponse()
    }

    @QueryMapping
    @PreAuthorize("hasAuthority('User')")
    fun callStatus(
        @Argument callId: String,
    ): CallResponse {
        val response = callService.getCallStatus(callId)
        return response.call.toResponse()
    }

    @QueryMapping
    @PreAuthorize("hasAuthority('User')")
    fun callRecords(
        @UserId userId: String,
        @Argument(name = "limit") limit: Int = 20,
        @Argument(name = "offset") offset: Int = 0,
    ): List<CallRecordResponse> {
        val response = callService.listCallRecords(userId, limit, offset)
        return response.recordsList.map { it.toResponse() }
    }

    @MutationMapping
    @PreAuthorize("hasAuthority('User')")
    fun rateCall(
        @UserId ratedBy: String,
        @Argument input: RateCallInput,
    ): CallRatingResponse {
        val response = callService.rateCall(
            callRecordId = input.callRecordId,
            ratedBy = ratedBy,
            ratedTo = input.ratedTo,
            rating = input.rating,
            comment = input.comment,
        )
        return response.rating.toResponse()
    }
}
